#include <iostream>
#include <string>
#include <vector>
#include <cstdlib>
#include <ctime>
#include <memory>

class Enemy {
private:
    std::string name;
    int health;
    int attackPower;
    bool isAlive;

public:
    Enemy(std::string n, int h, int a) 
        : name(n), health(h), attackPower(a), isAlive(true) {
        std::cout << "⚔️ " << name << " spawned! (HP: " << health << ", ATK: " << attackPower << ")" << std::endl;
    }

    ~Enemy() {
        if (isAlive) {
            std::cout << "💀 " << name << " escaped!" << std::endl;
        }
    }

    void takeDamage(int damage) {
        if (!isAlive) return;
        health -= damage;
        if (health <= 0) {
            health = 0;
            isAlive = false;
            std::cout << "💥 " << name << " defeated!" << std::endl;
        } else {
            std::cout << "⚡ " << name << " took " << damage << " damage! (HP: " << health << ")" << std::endl;
        }
    }

    void attack(Enemy* target) {
        if (!isAlive || target == nullptr || !target->isAlive) return;
        int damage = attackPower + (rand() % 5);
        std::cout << "🗡️ " << name << " attacks " << target->getName() << " for " << damage << " damage!" << std::endl;
        target->takeDamage(damage);
    }

    void display() const {
        std::cout << name << " (HP: " << health << "/?" << ", ATK: " << attackPower 
                  << ", " << (isAlive ? "Alive" : "Dead") << ")" << std::endl;
    }

    std::string getName() const { return name; }
    bool getIsAlive() const { return isAlive; }
};

// Enemy factory
Enemy* spawnEnemy(int level) {
    std::string names[] = {"Goblin", "Orc", "Skeleton", "Wolf", "Troll"};
    std::string name = names[rand() % 5];
    int health = 20 + (level * 10) + (rand() % 10);
    int attack = 5 + (level * 3) + (rand() % 5);
    return new Enemy(name, health, attack);
}

int main() {
    std::srand(std::time(0));

    std::cout << "=== Dynamic Enemy Spawning ===" << std::endl;

    // 1. Vector of enemy pointers
    std::vector<Enemy*> enemies;

    // 2. Spawn enemies
    std::cout << "\n--- Spawning enemies ---" << std::endl;
    int playerLevel = 1;
    for (int i = 0; i < 5; i++) {
        enemies.push_back(spawnEnemy(playerLevel));
    }

    // 3. Display all enemies
    std::cout << "\n--- Enemy Roster ---" << std::endl;
    for (size_t i = 0; i < enemies.size(); i++) {
        std::cout << i + 1 << ". ";
        enemies[i]->display();
    }

    // 4. Combat simulation
    std::cout << "\n--- Combat Simulation ---" << std::endl;
    for (size_t i = 0; i < enemies.size() && i + 1 < enemies.size(); i++) {
        if (enemies[i]->getIsAlive() && enemies[i+1]->getIsAlive()) {
            enemies[i]->attack(enemies[i+1]);
            if (enemies[i+1]->getIsAlive()) {
                enemies[i+1]->attack(enemies[i]);
            }
        }
    }

    // 5. Display survivors
    std::cout << "\n--- Survivors ---" << std::endl;
    for (Enemy* e : enemies) {
        if (e->getIsAlive()) {
            e->display();
        }
    }

    // 6. Clean up
    std::cout << "\n--- Cleanup ---" << std::endl;
    for (Enemy* e : enemies) {
        delete e;
    }
    enemies.clear();

    std::cout << "\n--- Using smart pointers ---" << std::endl;
    std::vector<std::unique_ptr<Enemy>> smartEnemies;
    for (int i = 0; i < 3; i++) {
        smartEnemies.push_back(std::make_unique<Enemy>("Smart Goblin", 30, 8));
    }
    // No manual delete needed!

    return 0;
}

