#include <iostream>
#include <string>
#include <vector>
#include <cstdlib>
#include <ctime>
#include <memory>

class Enemy {
private:
    std::string name;
    int health;

public:
    Enemy(std::string n, int h) : name(n), health(h) {
        std::cout << "Enemy " << name << " spawned!" << std::endl;
    }

    ~Enemy() {
        std::cout << "Enemy " << name << " destroyed!" << std::endl;
    }

    void display() const {
        std::cout << name << " (HP: " << health << ")" << std::endl;
    }

    bool isAlive() const { return health > 0; }
};

Enemy* spawnEnemy(int level) {
    std::string names[] = {"Goblin", "Orc", "Skeleton", "Wolf", "Troll"};
    std::string name = names[rand() % 5];
    int health = 20 + level * 10;
    return new Enemy(name, health);
}

int main() {
    std::srand(std::time(0));

    std::vector<Enemy*> enemies;

    for (int i = 0; i < 3; i++) {
        enemies.push_back(spawnEnemy(1));
    }
    for (int i = 0; i < 2; i++) {
        enemies.push_back(spawnEnemy(2));
    }

    std::cout << "\n=== Enemies ===" << std::endl;
    for (Enemy* e : enemies) {
        e->display();
    }

    for (Enemy* e : enemies) {
        delete e;
    }
    enemies.clear();

    std::cout << "\n=== Smart Pointers ===" << std::endl;
    std::vector<std::unique_ptr<Enemy>> smartEnemies;
    smartEnemies.push_back(std::make_unique<Enemy>("Smart Goblin", 30));
    smartEnemies.push_back(std::make_unique<Enemy>("Smart Orc", 50));

    for (const auto& e : smartEnemies) {
        e->display();
    }

    return 0;
}
